patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,14 +1,14 @@
 module mux4_to_1(
   input [3:0] data_in,
   input [1:0] sel,
-  output data_out
+  output out
 );
   assign data_out = data_in[sel];
 endmodule

 module wrapper(
   input [3:0] signals,
   input [1:0] selector,
-  output selected
+  output selected
 );
-  mux4_to_1 mux(.data_in(signals), .sel(selector), .output(selected));
+  mux4_to_1 mux(.data_in(signals), .sel(selector), .out(selected));
 endmodule

before_code:
module mux4_to_1(
  input [3:0] data_in,
  input [1:0] sel,
  output data_out
);
  assign data_out = data_in[sel];
endmodule

module wrapper(
  input [3:0] signals,
  input [1:0] selector,
  output selected
);
  mux4_to_1 mux(.data_in(signals), .sel(selector), .output(selected));
endmodule

after_code:
module mux4_to_1(
  input [3:0] data_in,
  input [1:0] sel,
  output out
);
  assign data_out = data_in[sel];
endmodule

module wrapper(
  input [3:0] signals,
  input [1:0] selector,
  output selected
);
  mux4_to_1 mux(.data_in(signals), .sel(selector), .out(selected));
endmodule
